+enum HistoryDiffSegmentKind: Equatable {
+    case unchanged
+    case inserted
+    case removed
+}
+
+struct HistoryDiffSegment: Equatable {
+    let kind: HistoryDiffSegmentKind
+    let text: String
+    let hasLeadingSpace: Bool
+
+    static func == (lhs: HistoryDiffSegment, rhs: HistoryDiffSegment) -> Bool {
+        lhs.kind == rhs.kind && lhs.text == rhs.text
+    }
+}
+
+enum HistoryDiffEngine {
+    static func diff(original: String, updated: String) -> [HistoryDiffSegment] {
+        let originalTokens = tokenize(original)
+        let updatedTokens = tokenize(updated)
+        let operations = lcsDiff(original: originalTokens, updated: updatedTokens)
+        let merged = merge(operations, separator: " ")
+        return refineSingleWordReplacements(in: merged)
+    }
+
+    static func reconstructPlainText(from segments: [HistoryDiffSegment]) -> String {
+        segments.reduce(into: "") { result, segment in
+            if segment.hasLeadingSpace, !result.isEmpty {
+                result.append(" ")
+            }
+            result.append(segment.text)
+        }
+    }
+
+    private static func tokenize(_ text: String) -> [String] {
+        text.split(whereSeparator: \.isWhitespace).map(String.init)
+    }
+
+    private static func lcsDiff(original: [String], updated: [String]) -> [HistoryDiffSegment] {
+        let lcs = lcsTable(lhs: original, rhs: updated)
+        var segments: [HistoryDiffSegment] = []
+        var row = original.count
+        var column = updated.count
+
+        while row > 0 || column > 0 {
+            if row > 0, column > 0, original[row - 1] == updated[column - 1] {
+                segments.append(
+                    HistoryDiffSegment(kind: .unchanged, text: original[row - 1], hasLeadingSpace: false)
+                )
+                row -= 1
+                column -= 1
+            } else if column > 0, (row == 0 || lcs[row][column - 1] >= lcs[row - 1][column]) {
+                segments.append(
+                    HistoryDiffSegment(kind: .inserted, text: updated[column - 1], hasLeadingSpace: false)
+                )
+                column -= 1
+            } else if row > 0 {
+                segments.append(
+                    HistoryDiffSegment(kind: .removed, text: original[row - 1], hasLeadingSpace: false)
+                )
+                row -= 1
+            }
+        }
+
+        return segments.reversed()
+    }
+
+    private static func lcsTable(lhs: [String], rhs: [String]) -> [[Int]] {
+        var table = Array(repeating: Array(repeating: 0, count: rhs.count + 1), count: lhs.count + 1)
+
+        guard !lhs.isEmpty, !rhs.isEmpty else {
+            return table
+        }
+
+        for row in 1...lhs.count {
+            for column in 1...rhs.count {
+                if lhs[row - 1] == rhs[column - 1] {
+                    table[row][column] = table[row - 1][column - 1] + 1
+                } else {
+                    table[row][column] = max(table[row - 1][column], table[row][column - 1])
+                }
+            }
+        }
+
+        return table
+    }
+
+    private static func merge(_ segments: [HistoryDiffSegment], separator: String) -> [HistoryDiffSegment] {
+        var merged: [HistoryDiffSegment] = []
+
+        for segment in segments where !segment.text.isEmpty {
+            if let last = merged.last, last.kind == segment.kind {
+                merged[merged.count - 1] = HistoryDiffSegment(
+                    kind: last.kind,
+                    text: last.text + separator + segment.text,
+                    hasLeadingSpace: last.hasLeadingSpace
+                )
+            } else {
+                merged.append(
+                    HistoryDiffSegment(
+                        kind: segment.kind,
+                        text: segment.text,
+                        hasLeadingSpace: !merged.isEmpty
+                    )
+                )
+            }
+        }
+
+        return merged
+    }
+
+    private static func refineSingleWordReplacements(in segments: [HistoryDiffSegment]) -> [HistoryDiffSegment] {
+        var refined: [HistoryDiffSegment] = []
+        var index = 0
+
+        while index < segments.count {
+            let current = segments[index]
+            guard
+                current.kind == .removed,
+                index + 1 < segments.count,
+                segments[index + 1].kind == .inserted,
+                !current.text.contains(" "),
+                !segments[index + 1].text.contains(" ")
+            else {
+                refined.append(current)
+                index += 1
+                continue
+            }
+
+            let replacement = characterLevelDiff(
+                removed: current,
+                inserted: segments[index + 1]
+            )
+            if replacement.contains(where: { $0.kind == .unchanged }) {
+                refined.append(contentsOf: replacement)
+            } else {
+                refined.append(current)
+                refined.append(segments[index + 1])
+            }
+            index += 2
+        }
+
+        return refined
+    }
+
+    private static func characterLevelDiff(
+        removed: HistoryDiffSegment,
+        inserted: HistoryDiffSegment
+    ) -> [HistoryDiffSegment] {
+        let removedCharacters = removed.text.map(String.init)
+        let insertedCharacters = inserted.text.map(String.init)
+        let merged = merge(lcsDiff(original: removedCharacters, updated: insertedCharacters), separator: "")
+
+        return merged.enumerated().map { index, segment in
+            HistoryDiffSegment(
+                kind: segment.kind,
+                text: segment.text,
+                hasLeadingSpace: index == 0 ? removed.hasLeadingSpace : false
+            )
+        }
+    }
+}
