+    private func styledText(for segment: HistoryDiffSegment) -> Text {
+        let prefix = segment.hasLeadingSpace ? " " : ""
+        let base = Text(prefix + segment.text)
+
+        switch segment.kind {
+        case .unchanged:
+            return base
+        case .inserted:
+            return base.foregroundColor(.green).bold().underline()
+        case .removed:
+            return base.foregroundColor(.red).strikethrough()
+        }
+    }
+}
