+struct SpeakerFilteringVisualizationModel {
+    let summary: DiarizationSummary
+    let audioDuration: TimeInterval
+
+    var totalDuration: TimeInterval {
+        max(audioDuration, summary.spans.map(\.endTime).max() ?? 0)
+    }
+
+    var summaryText: String {
+        if summary.usedFallback, let reason = summary.fallbackReason {
+            return "Fallback used because \(fallbackMessage(for: reason))."
+        }
+
+        if let targetSpeakerID = summary.targetSpeakerID {
+            return "Target speaker \(targetSpeakerID) kept \(formatDuration(summary.keptAudioDuration))."
+        }
+
+        return "Speaker filtering completed for this recording."
+    }
+
+    var targetSpeakerText: String {
+        summary.targetSpeakerID ?? "None"
+    }
+
+    var keptDurationText: String {
+        formatDuration(summary.keptAudioDuration)
+    }
+
+    var fallbackText: String {
+        guard summary.usedFallback else {
+            return "No"
+        }
+
+        guard let reason = summary.fallbackReason else {
+            return "Yes"
+        }
+
+        return fallbackMessage(for: reason)
+    }
+
+    func width(for span: DiarizationSpan, totalWidth: CGFloat) -> CGFloat {
+        guard totalDuration > 0 else {
+            return totalWidth
+        }
+
+        return max(3, CGFloat(span.duration / totalDuration) * totalWidth)
+    }
+
+    private func formatDuration(_ duration: TimeInterval?) -> String {
+        guard let duration else {
+            return "None"
+        }
+
+        return String(format: "%.2fs", duration)
+    }
+
+    private func fallbackMessage(for reason: SpeakerFilteringFallbackReason) -> String {
+        switch reason {
+        case .noUsableSpeakerSpans:
+            return "no usable speaker spans"
+        case .noSpeakerReachedThreshold:
+            return "no speaker reached the selection threshold"
+        case .insufficientKeptAudio:
+            return "kept audio was too short"
+        case .filteredAudioExtractionFailed:
+            return "filtered audio extraction failed"
+        case .emptyFilteredTranscription:
+            return "filtered transcription came back empty"
+        }
+    }
+}
